eligible_agents = {agent for agent, count in handled_cases_counts.items() if count > 0}

# Get transfer counts for eligible agents, defaulting to 0 if no transfers
eligible_agents_transfer_counts = {agent: transfer_counts.get(agent, 0) for agent in eligible_agents}

